import { useLocation, Link } from 'react-router-dom';
import useTierGate, { getUserTier, TIER_LEVELS } from '../hooks/useTierGate';
import useStripeCheckout from '../hooks/useStripeCheckout';
import GlassPanel from './ui/GlassPanel';
import { tokens } from '../styles/tokens';
import { AURA_TIERS, TIER_FEATURES, TIER_MONTHLY_MAP as PRICING_MAP, tierPrice, tierAnnualPrice } from '../config/pricing';

const T = {
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  blue: tokens.color.blue, purple: tokens.color.purple, amber: tokens.color.amber,
  green: tokens.color.green, red: tokens.color.red,
  surface2: tokens.color.surfaceHover, border: tokens.color.border,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

/**
 * Full pricing table for Aura Alpha tiers — derived from shared config/pricing.js
 */
const TIER_INFO = {
  starter: {
    color: T.blue,
    features: TIER_FEATURES.starter.featureList,
    price: tierPrice('starter'),
    annualPrice: tierAnnualPrice('starter'),
    monthlyNum: AURA_TIERS.starter.price,
  },
  trader: {
    color: T.green,
    features: TIER_FEATURES.trader.featureList,
    price: tierPrice('trader'),
    annualPrice: tierAnnualPrice('trader'),
    monthlyNum: AURA_TIERS.trader.price,
  },
  pro: {
    color: T.purple,
    features: TIER_FEATURES.pro.featureList,
    price: tierPrice('pro'),
    annualPrice: tierAnnualPrice('pro'),
    monthlyNum: AURA_TIERS.pro.price,
  },
  elite: {
    color: T.amber,
    features: TIER_FEATURES.elite.featureList,
    price: tierPrice('elite'),
    annualPrice: tierAnnualPrice('elite'),
    monthlyNum: AURA_TIERS.elite.price,
  },
  institutional: {
    color: '#E0E0E0',
    features: TIER_FEATURES.institutional.featureList,
    price: tierPrice('institutional'),
    annualPrice: tierAnnualPrice('institutional'),
    contactSales: true,
    monthlyNum: AURA_TIERS.institutional.price,
  },
};

const TIER_MONTHLY_MAP = PRICING_MAP;

/**
 * Get the price difference between user's current tier and the required tier.
 */
function getPriceDifference(userTier, requiredTier) {
  const current = TIER_MONTHLY_MAP[userTier] || 0;
  const required = TIER_MONTHLY_MAP[requiredTier] || 0;
  return Math.max(0, required - current);
}

/**
 * TierGate - Wraps page content and shows upgrade prompt if unauthorized.
 *
 * Usage:
 *   <TierGate><MyProtectedPage /></TierGate>
 *
 * Or with explicit tier requirement and feature description:
 *   <TierGate requiredTier="pro" feature="ML Analytics"><MyPage /></TierGate>
 *
 * Inline mode (blurs content with overlay instead of replacing):
 *   <TierGate requiredTier="starter" feature="Drawing tools" inline>
 *     <DrawingTools />
 *   </TierGate>
 */
export default function TierGate({ children, requiredTier, feature, inline = false }) {
  const location = useLocation();
  const gate = useTierGate(location.pathname);
  const { checkout, loading: checkoutLoading, error: checkoutError } = useStripeCheckout();

  const effectiveRequired = requiredTier || gate.requiredTier;
  const userTier = getUserTier();

  // Check access
  const canAccess = requiredTier
    ? (TIER_LEVELS[userTier] ?? 0) >= (TIER_LEVELS[requiredTier] ?? 0)
    : gate.canAccess;

  if (canAccess) return children;

  const info = TIER_INFO[effectiveRequired] || TIER_INFO.trader;
  const priceDiff = getPriceDifference(userTier, effectiveRequired);
  const tierLabel = {
    starter: 'Starter', trader: 'Trader', pro: 'Pro', elite: 'Elite', institutional: 'Institutional',
  }[effectiveRequired] || effectiveRequired;

  // Inline mode: blurred content with glass morphism overlay
  if (inline) {
    return (
      <div style={{ position: 'relative', minHeight: 80 }}>
        {/* Blurred content */}
        <div style={{
          filter: 'blur(6px)', opacity: 0.4, pointerEvents: 'none', userSelect: 'none',
        }}>
          {children}
        </div>

        {/* Glass overlay */}
        <div style={{
          position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center',
          background: 'rgba(11,15,20,0.55)', backdropFilter: 'blur(4px)',
          WebkitBackdropFilter: 'blur(4px)', borderRadius: 14,
          border: `1px solid ${info.color}25`,
          zIndex: 2,
        }}>
          <div style={{ textAlign: 'center', padding: '20px 24px', maxWidth: 380 }}>
            {/* Lock icon */}
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={info.color} strokeWidth="2"
              style={{ marginBottom: 8 }}>
              <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
              <path d="M7 11V7a5 5 0 0110 0v4" />
            </svg>
            <div style={{ fontSize: 14, fontWeight: 700, color: T.text, fontFamily: T.sans, marginBottom: 4 }}>
              {feature || `${tierLabel} Feature`}
            </div>
            <div style={{ fontSize: 12, color: T.textSec, marginBottom: 12, lineHeight: 1.4 }}>
              {priceDiff > 0
                ? `Upgrade for +$${priceDiff}/mo to unlock`
                : `Requires ${tierLabel} tier`
              }
            </div>
            <button
              onClick={() => checkout(effectiveRequired)}
              disabled={checkoutLoading}
              style={{
                padding: '8px 20px', borderRadius: 8, fontSize: 12, fontWeight: 700,
                fontFamily: T.mono, color: '#fff', border: 'none', cursor: 'pointer',
                background: `linear-gradient(135deg, ${info.color}, ${info.color}CC)`,
                boxShadow: `0 2px 10px ${info.color}33`,
                opacity: checkoutLoading ? 0.7 : 1,
              }}
            >
              {checkoutLoading ? 'Redirecting...' : `Unlock ${tierLabel}`}
            </button>
          </div>
        </div>
      </div>
    );
  }

  // Full-page gate (original behavior, enhanced)
  return (
    <div style={{
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      minHeight: '60vh', padding: 32, fontFamily: T.sans,
    }}>
      <GlassPanel style={{
        maxWidth: 480, textAlign: 'center', padding: 40,
        border: `1px solid ${info.color}22`,
        background: `linear-gradient(135deg, rgba(11,15,20,0.95), rgba(15,22,32,0.95))`,
      }}>
        {/* Lock icon */}
        <div style={{
          width: 64, height: 64, borderRadius: 14, margin: '0 auto 20px',
          background: info.color + '15', border: `2px solid ${info.color}33`,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}>
          <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke={info.color} strokeWidth="2">
            <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
            <path d="M7 11V7a5 5 0 0110 0v4" />
          </svg>
        </div>

        <h2 style={{ fontSize: 22, fontWeight: 700, color: T.text, margin: '0 0 8px' }}>
          {feature || `${tierLabel} Feature`}
        </h2>
        <p style={{ fontSize: 14, color: T.textSec, margin: '0 0 24px', lineHeight: 1.5 }}>
          This feature requires the <strong style={{ color: info.color }}>{tierLabel}</strong> tier or higher.
          {priceDiff > 0 && (
            <> Upgrade for just <strong style={{ color: info.color }}>+${priceDiff}/mo</strong> more.</>
          )}
        </p>

        {/* Features included */}
        <div style={{
          background: T.surface2, borderRadius: 10, padding: 16, marginBottom: 20,
          border: `1px solid ${T.border}`, textAlign: 'left',
        }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: T.textSec, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 12 }}>
            {tierLabel} Includes
          </div>
          <ul style={{ margin: 0, padding: 0, listStyle: 'none' }}>
            {info.features.map(f => (
              <li key={f} style={{
                display: 'flex', alignItems: 'center', gap: 8, padding: '6px 0',
                fontSize: 13, color: T.text,
              }}>
                <span style={{ color: info.color, fontSize: 14 }}>&#10003;</span>
                {f}
              </li>
            ))}
          </ul>
        </div>

        {/* Price + CTA */}
        <div style={{ marginBottom: 16 }}>
          {info.contactSales ? (
            <span style={{ fontSize: 22, fontWeight: 700, color: info.color, fontFamily: T.sans }}>Custom Pricing</span>
          ) : (
            <>
              <span style={{ fontSize: 28, fontWeight: 800, color: info.color, fontFamily: T.mono }}>{info.price}</span>
              {info.annualPrice && (
                <span style={{ fontSize: 14, color: T.textSec, marginLeft: 8 }}>or {info.annualPrice}</span>
              )}
            </>
          )}
        </div>

        {info.contactSales ? (
          <Link
            to="/contact-sales"
            style={{
              display: 'inline-block', padding: '12px 32px', borderRadius: 10,
              fontSize: 14, fontWeight: 700, color: '#fff', textDecoration: 'none',
              background: `linear-gradient(135deg, ${info.color}, ${info.color}CC)`,
              boxShadow: `0 4px 16px ${info.color}33`,
            }}
          >
            Contact Sales
          </Link>
        ) : (
          <button
            onClick={() => checkout(effectiveRequired)}
            disabled={checkoutLoading}
            style={{
              display: 'inline-block', padding: '12px 32px', borderRadius: 10,
              fontSize: 14, fontWeight: 700, color: '#fff', border: 'none', cursor: 'pointer',
              background: `linear-gradient(135deg, ${info.color}, ${info.color}CC)`,
              boxShadow: `0 4px 16px ${info.color}33`,
              opacity: checkoutLoading ? 0.7 : 1,
            }}
          >
            {checkoutLoading ? 'Redirecting...' : 'Upgrade Now'}
          </button>
        )}
        {checkoutError && (
          <div style={{ color: T.red, fontSize: 13, marginTop: 8 }}>{checkoutError}</div>
        )}

        <div style={{ marginTop: 12 }}>
          <Link to="/home" style={{ fontSize: 13, color: T.textSec, textDecoration: 'none' }}>
            Back to Dashboard
          </Link>
        </div>
      </GlassPanel>
    </div>
  );
}

export { TIER_INFO, TIER_MONTHLY_MAP, getPriceDifference };
